#include <memory>
#include <vector>

class FirmwareBuffer {
public:
    explicit FirmwareBuffer(size_t size)
        : m_buffer(std::make_unique<uint8_t[]>(size))
        , m_size(size)
    {}

    std::span<uint8_t> data() {
        return { m_buffer.get(), m_size };
    }

private:
    std::unique_ptr<uint8_t[]> m_buffer;
    size_t m_size;
};
